fix:
public void validate(Answer<?> answer, Invocation invocation) {
    if (answer == null) {
        throw new NullPointerException("answer is null");
    } else if (!answer.getClass().isInstance(invocation)) {
        throw new IllegalArgumentException("answer not applicable for given invocation");
    }

    if (answer instanceof ThrowsException) {
        validateException((ThrowsException) answer, invocation);
    } else if (answer instanceof Returns) {
        validateReturnValue((Returns) answer, invocation);
    } else if (answer instanceof DoesNothing) {
        validateDoNothing((DoesNothing) answer, invocation);
    } else {
        throw new UnsupportedOperationException("unexpected answer type: " + answer.getClass());
    }
}

